     2→
     3→import { getKycStatus } from "@/entities/kyc";
     4→import { getAddress, getProfile } from "@/entities/profile";
     5→import { ProfilePage } from "@/pages-layer/profile";
     6→import { ApiKeys } from "@/shared/api/query-keys";
     7→import { getQueryClientServer } from "@/shared/lib/api/get-query-client-server";
     8→
     9→export default async function Profile() {
    10→  const queryClient = getQueryClientServer();
    11→
    12→  await Promise.all([
    13→    queryClient.prefetchQuery({
    14→      queryKey: ApiKeys.profile(),
    15→      queryFn: getProfile,
    16→    }),
    17→    queryClient.prefetchQuery({
    18→      queryKey: ApiKeys.address(),
    19→      queryFn: getAddress,
    20→    }),
    21→    queryClient.prefetchQuery({
    22→      queryKey: ApiKeys.kycStatus(),
    23→      queryFn: getKycStatus,
    24→    }),
    25→  ]);
    26→
    27→  return (
    28→    <HydrationBoundary state={dehydrate(queryClient)}>
    29→      <ProfilePage />
    30→    </HydrationBoundary>
    31→  );
    32→}
