     1→import { ApiKeys, TagsEnum } from "@/shared/api/query-keys";
     2→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
     3→import type {
     4→  UpdateProfileDto,
     5→  UpdateSettingsDto,
     6→  UpsertAddressDto,
     7→  UserSettings,
     8→} from "../model/types";
     9→import * as profileService from "./services";
    10→
    11→export function useProfile() {
    12→  return useQuery({
    13→    queryKey: ApiKeys.profile(),
    14→    queryFn: profileService.getProfile,
    15→  });
    16→}
    17→
    18→export function useAddress() {
    19→  return useQuery({
    20→    queryKey: ApiKeys.address(),
    21→    queryFn: profileService.getAddress,
    22→    retry: false,
    23→  });
    24→}
    25→
    26→export function useUpdateProfile() {
    27→  const queryClient = useQueryClient();
    28→
    29→  return useMutation({
    30→    mutationFn: (data: UpdateProfileDto) => profileService.updateProfile(data),
    31→    onSuccess: () => {
    32→      queryClient.invalidateQueries({ queryKey: ApiKeys.profile() });
    33→    },
    34→  });
    35→}
    36→
    37→export function useUpsertAddress() {
    38→  const queryClient = useQueryClient();
    39→
    40→  return useMutation({
    41→    mutationFn: (data: UpsertAddressDto) => profileService.upsertAddress(data),
    42→    onSuccess: () => {
    43→      queryClient.invalidateQueries({ queryKey: ApiKeys.address() });
    44→    },
    45→  });
    46→}
    47→
    48→export function useDeleteAddress() {
    49→  const queryClient = useQueryClient();
    50→
    51→  return useMutation({
    52→    mutationFn: profileService.deleteAddress,
    53→    onSuccess: () => {
    54→      queryClient.invalidateQueries({ queryKey: ApiKeys.address() });
    55→    },
    56→  });
    57→}
    58→
    59→export function useUserSettings() {
    60→  return useQuery({
    61→    queryKey: ApiKeys.userSettings(),
    62→    queryFn: profileService.getUserSettings,
    63→    retry: false,
    64→  });
    65→}
    66→
    67→export function useUpdateUserSettings() {
    68→  const queryClient = useQueryClient();
    69→
    70→  return useMutation({
    71→    mutationFn: (data: UpdateSettingsDto) =>
    72→      profileService.updateUserSettings(data),
    73→    onMutate: async (newSettings) => {
    74→      const queryKey = ApiKeys.userSettings();
    75→
    76→      await queryClient.cancelQueries({ queryKey });
    77→
    78→      const previousSettings = queryClient.getQueryData<UserSettings>(queryKey);
    79→
    80→      queryClient.setQueryData<UserSettings>(queryKey, (old) => {
    81→        if (!old) return old;
    82→
    83→        return {
    84→          ...old,
    85→          ...newSettings,
    86→        };
    87→      });
    88→
    89→      return { previousSettings };
    90→    },
    91→    onError: (_error, _variables, context) => {
    92→      if (context?.previousSettings) {
    93→        queryClient.setQueryData(
    94→          ApiKeys.userSettings(),
    95→          context.previousSettings,
    96→        );
    97→      }
    98→    },
    99→    onSettled: () => {
   100→      queryClient.invalidateQueries({
   101→        queryKey: [TagsEnum.USER_SETTINGS],
   102→      });
   103→    },
   104→  });
   105→}
