     1→"use client";
     2→
     3→import {
     4→  UserSetting,
     5→  useUpdateUserSettings,
     6→  useUserSettings,
     7→  type UserNotificationsSetting,
     8→} from "@/entities/profile";
     9→import { Label } from "@/shared/ui/label";
    10→import { Loader } from "@/shared/ui/loader";
    11→import { toast } from "@/shared/ui/notification";
    12→import { Switch } from "@/shared/ui/switch";
    13→import { useCallback, useEffect, useRef, type FC } from "react";
    14→
    15→export const UserSettings: FC = () => {
    16→  const { data: userSettings, isLoading, isError } = useUserSettings();
    17→
    18→  const updateSettingsMutation = useUpdateUserSettings();
    19→
    20→  const debounceTimerRef = useRef<NodeJS.Timeout | null>(null);
    21→
    22→  useEffect(
    23→    () => () => {
    24→      if (debounceTimerRef.current) {
    25→        clearTimeout(debounceTimerRef.current);
    26→      }
    27→    },
    28→    [],
    29→  );
    30→
    31→  const handleToggle = useCallback(
    32→    (field: keyof UserNotificationsSetting, value: boolean) => {
    33→      const currentSettings = userSettings?.[UserSetting.Notifications];
    34→      if (!currentSettings) return;
    35→
    36→      const updatedNotifications = {
    37→        ...currentSettings,
    38→        [field]: value,
    39→      };
    40→
    41→      if (debounceTimerRef.current) {
    42→        clearTimeout(debounceTimerRef.current);
    43→      }
    44→
    45→      debounceTimerRef.current = setTimeout(() => {
    46→        updateSettingsMutation.mutate(
    47→          {
    48→            [UserSetting.Notifications]: updatedNotifications,
    49→          },
    50→          {
    51→            onSuccess: () => {
    52→              toast.success("Settings updated");
    53→            },
    54→            onError: () => {
    55→              toast.error("Failed to update settings");
    56→            },
    57→          },
    58→        );
    59→      }, 300);
    60→    },
    61→    [userSettings, updateSettingsMutation],
    62→  );
    63→
    64→  const notificationsSettings =
    65→    userSettings?.[UserSetting.Notifications] ?? null;
    66→
    67→  if (isLoading) {
    68→    return (
    69→      <div className="flex min-h-[400px] items-center justify-center">
    70→        <Loader />
    71→      </div>
    72→    );
    73→  }
    74→
    75→  if (isError || !userSettings || !userSettings[UserSetting.Notifications]) {
    76→    return (
    77→      <div className="flex min-h-[400px] items-center justify-center">
    78→        <p className="font-serif text-foreground">
    79→          Failed to load settings. Please try again.
    80→        </p>
    81→      </div>
    82→    );
    83→  }
    84→
    85→  return (
    86→    <div className="flex flex-col gap-6 p-8">
    87→      <h1 className="font-bold font-serif text-[32px] text-foreground leading-[1.199em]">
    88→        Settings
    89→      </h1>
    90→
    91→      <div>
    92→        <div className="rounded-[10px] border border-primary px-3 py-4">
    93→          <h2 className="font-bold font-serif text-foreground text-lg leading-[1.199em]">
    94→            Notification settings
    95→          </h2>
    96→        </div>
    97→        <div className="mt-3 flex flex-col gap-6 px-6">
    98→          <div className="flex items-center justify-between">
    99→            <div className="flex flex-col gap-1">
   100→              <Label className="font-bold font-serif text-[16px] text-base">
   101→                General Notification
   102→              </Label>
   103→              <span className="font-seri text-[14px] text-sm">
   104→                Enable all Notification for Updates and Alerts
   105→              </span>
   106→            </div>
   107→            <Switch
   108→              checked={notificationsSettings?.general ?? false}
   109→              onCheckedChange={(value) => handleToggle("general", value)}
   110→            />
   111→          </div>
   112→
   113→          <div className="flex items-center justify-between">
   114→            <div className="flex flex-col gap-1">
   115→              <Label className="font-bold font-serif text-[16px] text-base">
   116→                BuyBack Notifications
   117→              </Label>
   118→              <span className="font-serif text-[14px] text-sm">
   119→                Alerts for BuyBack Repayment, due dates etc
   120→              </span>
   121→            </div>
   122→            <Switch
   123→              checked={notificationsSettings?.buyback ?? false}
   124→              onCheckedChange={(value) => handleToggle("buyback", value)}
   125→            />
   126→          </div>
   127→
   128→          <div className="flex items-center justify-between">
   129→            <div className="flex flex-col gap-1">
   130→              <Label className="font-bold font-serif text-base">
   131→                Authenticator Notifications
   132→              </Label>
   133→              <span className="font-serif text-muted-foreground text-sm">
   134→                Alerts for authentication requests and updates
   135→              </span>
   136→            </div>
   137→            <Switch
   138→              checked={notificationsSettings?.authenticator ?? false}
   139→              onCheckedChange={(value) => handleToggle("authenticator", value)}
   140→            />
   141→          </div>
   142→
   143→          <div className="flex items-center justify-between text-[16px]">
   144→            <div className="flex flex-col gap-1">
   145→              <Label className="font-bold font-serif text-base">
   146→                Account Security Alerts
   147→              </Label>
   148→              <span className="font-serif text-[14px] text-sm">
   149→                Notifications for login attempts, password changes
   150→              </span>
   151→            </div>
   152→            <Switch
   153→              checked={notificationsSettings?.accountSecurity ?? false}
   154→              onCheckedChange={(value) =>
   155→                handleToggle("accountSecurity", value)
   156→              }
   157→            />
   158→          </div>
   159→        </div>
   160→      </div>
   161→    </div>
   162→  );
   163→};
