    24→export function useAuth(): UseAuthReturn {
    25→  const { data: session, status } = useSession();
    26→
    27→  const roles = session?.user.profile?.roles;
    28→
    29→  return {
    30→    isAuthenticated: !!session?.accessToken && status === "authenticated",
    31→    isLoading: status === "loading",
    32→    user: session?.user,
    33→    accessToken: session?.accessToken,
    34→    refreshToken: session?.refreshToken,
    35→    idToken: session?.idToken,
    36→    session: session?.session,
    37→    isAuthenticator:
    38→      (roles?.includes(UserRole.AUTHENTICATOR) && roles?.length === 1) ?? false,
    39→  };
    40→}
