        {children}
      </div>
    </div>
  );
}
```

**Sidebar Component:** `/Users/ilyakonyaev/work/coddtech/lux/lux-flow-fe/src/shared/ui/sidebar/sidebar.tsx` - This renders the navigation menu with Profile, Wallet, My Deals, Ticket, Settings, and Logout options.

---

### 2. Settings Page Location

**Page File:** `/Users/ilyakonyaev/work/coddtech/lux/lux-flow-fe/app/(app)/(protected)/settings/page.tsx`

This page renders the `<UserSettings>` widget component.

**Main Settings Widget:** `/Users/ilyakonyaev/work/coddtech/lux/lux-flow-fe/src/widgets/user-settings/ui/user-settings.tsx`

This component displays notification toggles with the following structure:
- **General Notification** - Enable all notifications for updates and alerts
- **BuyBack Notifications** - Alerts for buyback repayment, due dates, etc.
- **Authenticator Notifications** - Alerts for authentication requests and updates
- **Account Security Alerts** - Notifications for login attempts, password changes

The settings are managed through:
- `useUserSettings()` hook - fetches user notification settings
- `useUpdateUserSettings()` mutation - updates settings with debouncing (300ms)

---

### 3. Auth Provider & Session Storage

The authentication system uses **NextAuth.js with JWT strategy**. Here's how the auth provider is stored:

**Session Type Definition:** `/Users/ilyakonyaev/work/coddtech/lux/lux-flow-fe/src/shared/types/next-auth.d.ts`

```tsx
declare module "next-auth" {
  interface Session {
    accessToken: string;
    refreshToken: string;
    idToken: string;
    refreshTokenExpiresAt?: number;
    session?: string;
    isTemporaryPassword?: boolean;
    tempPasswordSession?: string;
    user: {
      id: string;
      email: string;
      profile?: Profile;
    } & DefaultSession["user"];
  }

  interface User {
    id: string;
    email: string;
    accessToken: string;
    refreshToken: string;
    idToken: string;
    refreshTokenExpiresAt?: number;
    session?: string;
    profile?: Profile;
    isTemporaryPassword?: boolean;
    tempPasswordSession?: string;
  }
}
```

**Auth Configuration:** `/Users/ilyakonyaev/work/coddtech/lux/lux-flow-fe/src/shared/config/auth-config.ts`

Uses **CredentialsProvider** (email/password authentication) with:
- JWT token strategy
- Automatic token refresh (when token < 60 seconds to expiry)
- Profile data fetched and stored in session after sign-in

**useProfile Hook Return Type:** `/Users/ilyakonyaev/work/coddtech/lux/lux-flow-fe/src/entities/profile/api/query-hooks.ts`

```tsx
export function useProfile() {
  return useQuery({
    queryKey: ApiKeys.profile(),
