}
```

Returns `Profile` entity type from `/Users/ilyakonyaev/work/coddtech/lux/lux-flow-fe/src/entities/profile/model/types.ts`:

```tsx
export interface Profile {
  id: string;
  fullName: string;
  email: string;
  phone: string;
  roles: UserRole[];
  selectedRole: UserRole;
  admin?: Admin;
  createdAt: string;
  updatedAt: string;
}
```

**useAuth Hook:** `/Users/ilyakonyaev/work/coddtech/lux/lux-flow-fe/src/entities/auth/model/use-auth.ts`

```tsx
export function useAuth(): UseAuthReturn {
  const { data: session, status } = useSession();
  const roles = session?.user.profile?.roles;

  return {
    isAuthenticated: !!session?.accessToken && status === "authenticated",
    isLoading: status === "loading",
    user: session?.user,
    accessToken: session?.accessToken,
    refreshToken: session?.refreshToken,
    idToken: session?.idToken,
    session: session?.session,
    isAuthenticator: (roles?.includes(UserRole.AUTHENTICATOR) && roles?.length === 1) ?? false,
  };
}
```

**Note:** The system currently uses only **Email/Password** authentication (CredentialsProvider). While the profile page displays a "Google" badge (hardcoded in the UI at line 145 of profile-page.tsx), there's no actual Google OAuth provider configured in the auth setup. The "Verified" badge next to the name is static.

